#!/usr/bin/env python3
"""Generate fully-translated .po files from .pot templates.

Reads `<addon>/i18n/<addon>.pot` for every addon in ADDONS and writes
`<addon>/i18n/<lang>.po` for every language in LANGUAGES, applying
translations from TRANSLATIONS[lang].

Missing translations fall back to the English msgid (gettext convention
for empty msgstr). Run this after `make i18n-export` regenerates the
`.pot` files — new strings land in the dicts below, re-run this script,
re-run msgfmt.

Usage:
    python scripts/i18n_translate.py

Verify:
    make i18n-check      # runs msgfmt -cv on every .po
"""

from __future__ import annotations

import sys
from pathlib import Path

ADDONS_ROOT = Path(__file__).resolve().parent.parent

ADDONS = [
    "pdfgeneratorapi_connector",
    "pdfgeneratorapi_connector_account",
    "pdfgeneratorapi_connector_sale",
    "pdfgeneratorapi_connector_purchase",
    "pdfgeneratorapi_connector_stock",
    "pdfgeneratorapi_connector_mrp",
    "pdfgeneratorapi_connector_rental",
]

# (native name, plural-forms header). Plural-forms are the canonical GNU
# gettext strings per locale.
LANGUAGES: dict[str, tuple[str, str]] = {
    "es": ("Spanish", "nplurals=2; plural=(n != 1);"),
    "pt_BR": ("Brazilian Portuguese", "nplurals=2; plural=(n > 1);"),
    "it": ("Italian", "nplurals=2; plural=(n != 1);"),
    "de": ("German", "nplurals=2; plural=(n != 1);"),
    "fr": ("French", "nplurals=2; plural=(n > 1);"),
    "cs": ("Czech", "nplurals=3; plural=(n==1) ? 0 : (n>=2 && n<=4) ? 1 : 2;"),
    "sk": ("Slovak", "nplurals=3; plural=(n==1) ? 0 : (n>=2 && n<=4) ? 1 : 2;"),
    "et": ("Estonian", "nplurals=2; plural=(n != 1);"),
}

# -----------------------------------------------------------------------------
# Translations. One dict per language. Keys are msgids exactly as they appear
# in the .pot files; values are the target-language msgstr. `None` or missing
# keys produce empty msgstr → Odoo falls back to English.
#
# Keep these in sync across languages — if you add a key to `es`, add it to
# every other language too. `msgfmt -cv` catches gettext-syntax errors but
# WON'T warn about missing entries. Grep for a string in this file before
# assuming it's untranslated.
# -----------------------------------------------------------------------------

